import { createReadStream, createWriteStream, readFileSync, writeFileSync } from "fs";
import { FlacStreamTagger } from "./dist/index.js";

export const tags = {
	tagMap: {
		title: "test-title",
		artist: ["artist 1", "artist 2"],
		album: "test-album",
		albumSortOrder: "TEST001",
	},
	picture: {
		buffer: readFileSync("./src/test/cover.jpg"),
	},
};

const tagger = createReadStream("./src/test/harpy.flac").pipe(new FlacStreamTagger(tags));
//tagger.pipe(createWriteStream("./src/test/harpy.out.flac"));
tagger.toBuffer().then((buffer) => writeFileSync("./src/test/harpy.out.flac", buffer));
